 简介 # 介绍 # Gin是一个golang的微框架，封装比较优雅，API友好，源码注释比较明确，具有快速灵活，容错方便等特点 对于golang而言，web框架的依赖要远比Python，Java之类的要小。自身的net/http足够简单，性能也非常不错 借助框架开发，不仅可以省去很多常用的封装带来的时间，也有助于团队的编码风格和形成规范 安装 # 要安装Gin软件包，您需要安装Go并首先设置Go工作区。
1.首先需要安装Go（需要1.10+版本），然后可以使用下面的Go命令安装Gin。
go get -u github.com/gin-gonic/gin
2.将其导入您的代码中：
import &ldquo;github.com/gin-gonic/gin&rdquo;
3.（可选）导入net/http。例如，如果使用常量，则需要这样做http.StatusOK。
import &ldquo;net/http&rdquo;
hello word # package main import ( &#34;net/http&#34; &#34;github.com/gin-gonic/gin&#34; ) func main() { // 1.创建路由 r := gin.Default() // 2.绑定路由规则，执行的函数 // gin.Context，封装了request和response r.GET(&#34;/&#34;, func(c *gin.Context) { c.String(http.StatusOK, &#34;hello World!&#34;) }) // 3.监听端口，默认在8080 // Run(&#34;里面不指定端口号默认为8080&#34;) r.Run(&#34;:8000&#34;) } GORM # 特性 # 全功能 ORM 关联 (Has One，Has Many，Belongs To，Many To Many，多态，单表继承) Create，Save，Update，Delete，Find 中钩子方法 支持 Preload、Joins 的预加载 事务，嵌套事务，Save Point，Rollback To Saved Point Context、预编译模式、DryRun 模式 批量插入，FindInBatches，Find/Create with Map，使用 SQL 表达式、Context Valuer 进行 CRUD SQL 构建器，Upsert，数据库锁，Optimizer/Index/Comment Hint，命名参数，子查询 复合主键，索引，约束 Auto Migration 自定义 Logger 灵活的可扩展插件 API：Database Resolver（多数据库，读写分离）、Prometheus… 每个特性都经过了测试的重重考验 开发者友好 安装 # go get -u gorm.io/gorm go get -u gorm.io/driver/sqlite 快速入门 # package main import ( &#34;gorm.io/gorm&#34; &#34;gorm.io/driver/sqlite&#34; ) type Product struct { gorm.Model Code string Price uint } func main() { db, err := gorm.Open(sqlite.Open(&#34;test.db&#34;), &amp;gorm.Config{}) if err != nil { panic(&#34;failed to connect database&#34;) } // 迁移 schema db.AutoMigrate(&amp;Product{}) // Create db.Create(&amp;Product{Code: &#34;D42&#34;, Price: 100}) // Read var product Product db.First(&amp;product, 1) // 根据整形主键查找 db.First(&amp;product, &#34;code = ?&#34;, &#34;D42&#34;) // 查找 code 字段值为 D42 的记录 // Update - 将 product 的 price 更新为 200 db.Model(&amp;product).Update(&#34;Price&#34;, 200) // Update - 更新多个字段 db.Model(&amp;product).Updates(Product{Price: 200, Code: &#34;F42&#34;}) // 仅更新非零值字段 db.Model(&amp;product).Updates(map[string]interface{}{&#34;Price&#34;: 200, &#34;Code&#34;: &#34;F42&#34;}) // Delete - 删除 product db.Delete(&amp;product, 1) }
